/*
 * Hill Cipher Implementation in C
 * university 2022 Scheme - Module 1: Classical Encryption Techniques
 * Block Size: 2x2 Matrix
 */

#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MOD 26

// Function prototypes
int modInverse(int a, int m);
void matrixInverse(int key[2][2], int inv[2][2]);
void encryptHill(char *plaintext, int key[2][2], char *ciphertext);
void decryptHill(char *ciphertext, int key[2][2], char *plaintext);
void textToNumbers(char *text, int *nums, int *len);
void numbersToText(int *nums, int len, char *text);

// Find modular multiplicative inverse using extended Euclidean algorithm
int modInverse(int a, int m) {
 int m0 = m;
 int y = 0;
 int x = 1;

 if (m == 1)
 return 0;

 while (a > 1) {
 int q = a / m;
 int t = m;

 // m is temporary remainder
 m = a % m;
 a = t;

 t = y;
 y = x - q * y;
 x = t;
 }

 // Make x positive
 if (x < 0)
 x += m0;

 return x;
}

// Calculate inverse of 2x2 matrix modulo 26
// K^-1 = (det^-1 * adj(K)) mod 26
void matrixInverse(int key[2][2], int inv[2][2]) {
 int det = (key[0][0] * key[1][1] - key[0][1] * key[1][0]) % MOD;
 if (det < 0)
 det += MOD;

 // Find modular inverse of determinant
 int detInv = modInverse(det, MOD);

 // Adjugate matrix: [[d, -b], [-c, a]]
 int adj[2][2];
 adj[0][0] = key[1][1] % MOD;
 adj[0][1] = (-key[0][1]) % MOD;
 adj[1][0] = (-key[1][0]) % MOD;
 adj[1][1] = key[0][0] % MOD;

 // Handle negative values
 for (int i = 0; i < 2; i++) {
 for (int j = 0; j < 2; j++) {
 if (adj[i][j] < 0)
 adj[i][j] += MOD;
 }
 }

 // K^-1 = detInv * adj mod 26
 inv[0][0] = (detInv * adj[0][0]) % MOD;
 inv[0][1] = (detInv * adj[0][1]) % MOD;
 inv[1][0] = (detInv * adj[1][0]) % MOD;
 inv[1][1] = (detInv * adj[1][1]) % MOD;
}

// Convert text to numbers (A=0, B=1, ..., Z=25)
void textToNumbers(char *text, int *nums, int *len) {
 *len = 0;
 for (int i = 0; text[i] != '\0'; i++) {
 if (isalpha(text[i])) {
 nums[*len] = toupper(text[i]) - 'A';
 (*len)++;
 }
 }
}

// Convert numbers back to text
void numbersToText(int *nums, int len, char *text) {
 for (int i = 0; i < len; i++) {
 text[i] = 'A' + nums[i];
 }
 text[len] = '\0';
}

// Encrypt using Hill Cipher
void encryptHill(char *plaintext, int key[2][2], char *ciphertext) {
 int nums[100];
 int len;

 // Convert and pad
 textToNumbers(plaintext, nums, &len);

 if (len % 2 != 0) {
 nums[len++] = 23; // X = 23 for padding
 }

 // Encrypt each 2-letter block
 int result[100];
 for (int i = 0; i < len; i += 2) {
 int p1 = nums[i];
 int p2 = nums[i+1];

 // C = K * P mod 26
 result[i] = (key[0][0] * p1 + key[0][1] * p2) % MOD;
 result[i+1] = (key[1][0] * p1 + key[1][1] * p2) % MOD;
 }

 numbersToText(result, len, ciphertext);
}

// Decrypt using Hill Cipher
void decryptHill(char *ciphertext, int key[2][2], char *plaintext) {
 int nums[100];
 int len;

 textToNumbers(ciphertext, nums, &len);

 // Find inverse key
 int inv[2][2];
 matrixInverse(key, inv);

 // Decrypt each block: P = K^-1 * C mod 26
 int result[100];
 for (int i = 0; i < len; i += 2) {
 int c1 = nums[i];
 int c2 = nums[i+1];

 result[i] = (inv[0][0] * c1 + inv[0][1] * c2) % MOD;
 result[i+1] = (inv[1][0] * c1 + inv[1][1] * c2) % MOD;
 }

 numbersToText(result, len, plaintext);
}

int main() {
 // Key matrix K = [[3,3],[2,5]] from textbook
 int key[2][2] = {{3, 3}, {2, 5}};

 // Verify key is valid
 int det = (key[0][0] * key[1][1] - key[0][1] * key[1][0]) % MOD;
 if (det < 0) det += MOD;

 printf("=== Hill Cipher Implementation ===\n\n");
 printf("Key Matrix K = [[%d, %d], [%d, %d]]\n", 
 key[0][0], key[0][1], key[1][0], key[1][1]);
 printf("Determinant: %d, gcd(%d, 26) = 1 - Valid Key\n\n", det, det);

 // Calculate and display inverse key
 int inv[2][2];
 matrixInverse(key, inv);
 printf("Inverse Key K^-1 = [[%d, %d], [%d, %d]]\n\n", 
 inv[0][0], inv[0][1], inv[1][0], inv[1][1]);

 // Test encryption
 char plaintext[] = "HELP"; // Padded with X
 char ciphertext[100];

 encryptHill(plaintext, key, ciphertext);
 printf("Encryption:\n");
 printf(" Plaintext: %s\n", plaintext);
 printf(" Ciphertext: %s\n\n", ciphertext);

 // Test decryption
 char decrypted[100];
 decryptHill(ciphertext, key, decrypted);
 printf("Decryption:\n");
 printf(" Ciphertext: %s\n", ciphertext);
 printf(" Plaintext: %s\n\n", decrypted);

 // Show step-by-step for first block
 printf("=== Step-by-Step for 'VT' block ===\n");
 int V = 21, T = 19; // V=21, T=19
 printf("Plaintext vector P = [%d, %d] (V, T)\n", V, T);

 int c1 = (3*V + 3*T) % 26;
 int c2 = (2*V + 5*T) % 26;
 printf("C = K * P = [[3,3],[2,5]] * [%d,%d]\n", V, T);
 printf("C = [%d, %d] mod 26\n", c1, c2);
 printf("Ciphertext: %c%c (Q, H)\n", 'A'+c1, 'A'+c2);

 return 0;
}
